import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';
import { prefetch } from '../utils/prefetch';
import { PAPER_BOTS } from '../utils/constants';

// Cache of last-close prices fetched from OHLCV
const priceCache = {};

// Crypto symbols that need region=crypto for chart data
const CRYPTO_EXCHANGES = new Set(['KRAKEN', 'PAXOS', 'ZEROHASH', 'COINBASE', 'BINANCE']);
const CRYPTO_ASSETS = new Set([
  'BTC', 'ETH', 'SOL', 'AVAX', 'ARB', 'AAVE', 'BNB', 'CRV', 'LINK', 'DOT',
  'ADA', 'ATOM', 'NEAR', 'SUI', 'XRP', 'LTC', 'DOGE', 'MATIC', 'UNI', 'FIL',
  'APT', 'OP', 'INJ', 'TIA', 'SEI', 'RENDER', 'FET', 'AGIX', 'OCEAN',
]);

function isCryptoPosition(pos) {
  if (pos.asset_class === 'crypto') return true;
  if (pos.exchange && CRYPTO_EXCHANGES.has(pos.exchange.toUpperCase())) return true;
  const base = (pos.symbol || '').split(/[-/]/)[0].toUpperCase();
  return CRYPTO_ASSETS.has(base);
}

async function enrichWithPrices(positions) {
  // Find positions missing a live price
  const needPrice = positions.filter(p =>
    p.symbol && (p.currentPrice == null || p.currentPrice === 0) && !priceCache[p.symbol]
  );
  // Fetch last close for each unique symbol (in parallel, max 10)
  const symbols = [...new Set(needPrice.map(p => p.symbol))].slice(0, 10);
  // Build a lookup of which symbols are crypto
  const cryptoSet = new Set(needPrice.filter(p => isCryptoPosition(p)).map(p => p.symbol));
  await Promise.all(symbols.map(async (sym) => {
    try {
      const region = cryptoSet.has(sym) ? 'crypto' : 'us';
      const data = await api('/charts/ohlcv/' + encodeURIComponent(sym) + '?bars=10&region=' + region);
      const bars = data?.bars || data?.data || [];
      if (bars.length > 0) {
        const last = bars[bars.length - 1];
        priceCache[sym] = last.close ?? last.c ?? last.price ?? null;
      }
    } catch {}
  }));

  return positions.map(p => {
    const cachedPrice = priceCache[p.symbol];
    if (cachedPrice && (p.currentPrice == null || p.currentPrice === 0)) {
      const qty = p.qty ?? p.quantity ?? 0;
      const avgCost = p.entryPrice ?? p.avg_cost ?? 0;
      const side = (p.side || '').toUpperCase();
      const isShort = side === 'SHORT' || side === 'SELL' || qty < 0;
      const absQty = Math.abs(qty);
      const priceDiff = cachedPrice - avgCost;
      const unrealizedPnl = isShort ? -absQty * priceDiff : absQty * priceDiff;
      const rawPct = avgCost > 0 ? (priceDiff / avgCost) * 100 : 0;
      return {
        ...p,
        currentPrice: cachedPrice,
        unrealizedPnl: unrealizedPnl,
        marketValue: absQty * cachedPrice,
        pctChange: isShort ? -rawPct : rawPct,
      };
    }
    return p;
  });
}

// Normalize a raw position from the API into the shape pages expect
function normalizePosition(raw) {
  const entryPrice = raw.entry_price ?? raw.entryPrice ?? raw.avg_cost ?? null;
  const entryDate = raw.entry_date ?? raw.entryDate ?? raw.entryTime ?? raw.timestamp ?? null;
  const side = raw.side ?? raw.direction ?? null;
  const qty = raw.qty ?? raw.quantity ?? 0;
  // Calculate duration from entry date
  let duration = raw.duration ?? null;
  if (duration == null && entryDate) {
    const entryMs = new Date(entryDate).getTime();
    if (!isNaN(entryMs)) {
      duration = Date.now() - entryMs;
    }
  }
  return {
    ...raw,
    entryPrice,
    side,
    qty,
    duration,
    // Keep snake_case originals for hooks that need them
    entry_date: entryDate,
  };
}

// Extract positions from telemetry data when /api/positions is auth-gated
function positionsFromTelemetry(telData) {
  const bots = telData?.bots;
  if (!bots || typeof bots !== 'object') return [];
  const allPos = [];
  for (const [botName, info] of Object.entries(bots)) {
    const payload = info?.payload || {};
    const positions = payload.positions || [];
    for (const p of positions) {
      allPos.push({
        symbol: p.symbol,
        qty: p.qty ?? p.quantity ?? p.position ?? 0,
        avg_cost: p.avg_cost ?? p.avgCost ?? p.entry_price ?? 0,
        entry_price: p.entry_price ?? p.avg_cost ?? p.avgCost ?? 0,
        side: (p.side || (p.qty < 0 ? 'SHORT' : 'LONG')),
        bot: botName,
        bot_name: botName,
        exchange: p.exchange || '',
        conId: p.conId || null,
      });
    }
  }
  return allPos;
}

export default function usePositions() {
  // Seed from prefetch cache for instant first render
  const prefetchedPos = prefetch.get('positions');
  const [positions, setPositions] = useState(() => {
    if (prefetchedPos) {
      const rawArr = Array.isArray(prefetchedPos) ? prefetchedPos : prefetchedPos.positions;
      return Array.isArray(rawArr) ? rawArr.map(normalizePosition) : [];
    }
    return [];
  });
  const [orders, setOrders] = useState(() => {
    const cached = prefetch.get('orders');
    if (cached) {
      const ordArr = Array.isArray(cached) ? cached : cached.orders;
      return Array.isArray(ordArr) ? ordArr : [];
    }
    return [];
  });
  const [riskExposure, setRiskExposure] = useState(null);
  const [portfolioSnapshot, setPortfolioSnapshot] = useState(null);
  const [loading, setLoading] = useState(!prefetchedPos);
  const enriched = useRef(false);
  const hasLoaded = useRef(!!prefetchedPos);

  const fetchAll = useCallback(async () => {
    if (!hasLoaded.current) setLoading(true);

    // Fetch positions, orders, telemetry, risk exposure, and portfolio snapshot
    const [posData, ordData, telData, riskData, snapData] = await Promise.all([
      api('/positions', { silent: true }).catch(() => null),
      api('/positions/orders', { silent: true }).catch(() => null),
      api('/telemetry/latest', { silent: true }).catch(() => null),
      api('/risk/exposure', { silent: true }).catch(() => null),
      api('/portfolio-brain/snapshot', { silent: true }).catch(() => null),
    ]);

    // PAPER_BOTS imported from constants — never shown in live trading views
    const isLiveBotPos = (p) => !PAPER_BOTS.has((p?.bot || p?.bot_name || '').toLowerCase());

    let pos = [];

    // Primary: use /api/positions if available
    if (posData) {
      const rawArr = Array.isArray(posData) ? posData : posData.positions;
      const raw = Array.isArray(rawArr) ? rawArr : [];
      pos = raw.filter(isLiveBotPos).map(normalizePosition);
    } else if (telData) {
      // Fallback: extract positions from telemetry data
      pos = positionsFromTelemetry(telData).filter(isLiveBotPos).map(normalizePosition);
    }

    // Enrich positions with strategy/bot from portfolio snapshot
    if (snapData && pos.length > 0) {
      const snapPositions = snapData?.positions || snapData?.bots || {};
      // Build lookup: symbol -> { strategy, bot, sector, industry, risk_contribution }
      const snapLookup = {};
      if (Array.isArray(snapPositions)) {
        for (const sp of snapPositions) {
          if (sp.symbol) snapLookup[sp.symbol] = sp;
        }
      } else if (typeof snapPositions === 'object') {
        for (const [botName, botData] of Object.entries(snapPositions)) {
          const botPositions = botData?.positions || [];
          for (const sp of botPositions) {
            if (sp.symbol) snapLookup[sp.symbol] = { ...sp, bot: botName };
          }
        }
      }
      pos = pos.map(p => {
        const snap = snapLookup[p.symbol];
        if (snap) {
          return {
            ...p,
            strategy: p.strategy || snap.strategy || snap.strategy_name || null,
            bot: p.bot || snap.bot || snap.bot_name || null,
            bot_name: p.bot_name || snap.bot_name || snap.bot || null,
            sector: p.sector || snap.sector || null,
            industry: p.industry || snap.industry || null,
            risk_contribution: p.risk_contribution ?? snap.risk_contribution ?? snap.risk_pct ?? null,
          };
        }
        return p;
      });
    }

    // Enrich with risk exposure data per symbol
    if (riskData && pos.length > 0) {
      const exposures = riskData?.exposures || riskData?.positions || [];
      const expLookup = {};
      if (Array.isArray(exposures)) {
        for (const e of exposures) {
          if (e.symbol) expLookup[e.symbol] = e;
        }
      }
      pos = pos.map(p => {
        const exp = expLookup[p.symbol];
        if (exp) {
          return {
            ...p,
            risk_contribution: p.risk_contribution ?? exp.risk_contribution ?? exp.risk_pct ?? null,
            sector: p.sector || exp.sector || null,
            industry: p.industry || exp.industry || null,
          };
        }
        return p;
      });
    }

    // Enrich with cached OHLCV prices
    if (pos.length > 0 && (!enriched.current || pos.some(p => p.currentPrice == null || p.currentPrice === 0))) {
      pos = await enrichWithPrices(pos);
      enriched.current = true;
    }
    setPositions(pos);

    if (ordData) {
      const ordArr = Array.isArray(ordData) ? ordData : ordData.orders;
      setOrders(Array.isArray(ordArr) ? ordArr : []);
    }
    if (riskData) setRiskExposure(riskData);
    if (snapData) setPortfolioSnapshot(snapData);
    setLoading(false);
    hasLoaded.current = true;
  }, []);

  useEffect(() => {
    fetchAll();
    const interval = setInterval(fetchAll, 30000);  // 30s — was 10s
    return () => clearInterval(interval);
  }, [fetchAll]);

  return { positions, orders, riskExposure, portfolioSnapshot, loading, fetchPositions: fetchAll, fetchData: fetchAll };
}
